File Routing Conventions

home.tsx → /
blog.tsx → /blog (layout)
blog._index.tsx → /blog (index inside layout)
blog.$slug.tsx → /blog/:slug
blog.$slug.edit.tsx → /blog/:slug/edit
_auth.tsx → layout, no URL segment
_auth.login.tsx → /login (inside _auth layout)
$.tsx → catch-all / 404

Enter fullscreen mode

Exit fullscreen mode

Or use explicit config in app/routes.ts:

import { type RouteConfig, route, index, layout } from '@react-router/dev/routes'
export default [
index('routes/home.tsx'),
layout('routes/_auth.tsx', [
route('login', 'routes/login.tsx'),
route('signup', 'routes/signup.tsx'),
]),
] satisfies RouteConfig

