Loaders: Server Data Fetching

// app/routes/blog.$slug.tsx
import { useLoaderData, redirect } from 'react-router'
import type { Route } from './+types/blog.$slug'
import { db } from '~/lib/db.server'
export async function loader({ params, request }: Route.LoaderArgs) {
const post = await db.posts.findUnique({
where: { slug: params.slug, published: true },
include: { author: true }
})
if (!post) throw new Response('Not Found', { status: 404 })
return { post }
}
export function meta({ data }: Route.MetaArgs) {
return [
{ title: data?.post.title },
{ name: 'description', content: data?.post.excerpt }
]
}
export default function BlogPost() {
const { post } = useLoaderData<typeof loader>()
// post is fully typed — no manual type annotation needed
return (
<article>
<h1>{post.title}</h1>
<p>By {post.author.name}</p>
<div dangerouslySetInnerHTML={{ __html: post.content }} />
</article>
)
}

Enter fullscreen mode

Exit fullscreen mode

params.slug is typed as string (not string | undefined) — the types are auto-generated based on your route filename. useLoaderData<typeof loader>() returns the exact shape your loader returns.

Auth in layout loaders

// app/routes/(protected)/+layout.server.ts
export async function loader({ locals, url }: Route.LoaderArgs) {
const session = await getSession(request)
if (!session.userId) {
throw redirect(`/login?next=${encodeURIComponent(url.pathname)}`)
}
return { user: session.user }
}

Enter fullscreen mode

Exit fullscreen mode

All routes inside this layout automatically require auth.

Actions: Server Mutations

// app/routes/blog.$slug.edit.tsx
import { Form, useActionData, redirect } from 'react-router'
import { z } from 'zod'
import type { Route } from './+types/blog.$slug.edit'
const schema = z.object({
title: z.string().min(1).max(200),
content: z.string().min(1),
published: z.coerce.boolean().default(false)
})
export async function action({ params, request }: Route.ActionArgs) {
const { user } = await requireAuth(request)
const formData = await request.formData()
const parsed = schema.safeParse(Object.fromEntries(formData))
if (!parsed.success) {
return {
errors: parsed.error.flatten().fieldErrors,
values: Object.fromEntries(formData)
}
}
const post = await db.posts.update({
where: { slug: params.slug, authorId: user.id },
data: parsed.data
})
throw redirect(`/blog/${post.slug}`)
}
export default function EditPost() {
const { post } = useLoaderData<typeof loader>()
const actionData = useActionData<typeof action>()
return (
<Form method="post">
<input
name="title"
defaultValue={actionData?.values?.title ?? post.title}
/>
{actionData?.errors?.title && (
<p className="error">{actionData.errors.title[0]}</p>
)}
<button type="submit">Save</button>
</Form>
)
}

