useFetcher: Mutations Without Navigation

import { useFetcher } from 'react-router'
function LikeButton({ postId, initialLikes, isLiked }: Props) {
const fetcher = useFetcher()
// Optimistic UI: read in-flight form data
const optimisticLiked = fetcher.formData
? fetcher.formData.get('liked') === 'true'
: isLiked
const optimisticCount = fetcher.formData
? initialLikes + (optimisticLiked ? 1 : -1)
: initialLikes
return (
<fetcher.Form method="post" action="/api/likes">
<input type="hidden" name="postId" value={postId} />
<input type="hidden" name="liked" value={String(!optimisticLiked)} />
<button type="submit">
{optimisticLiked ? '❤️' : '🤍'} {optimisticCount}
</button>
</fetcher.Form>
)
}

Enter fullscreen mode

Exit fullscreen mode

fetcher.formData gives you in-flight data for optimistic UI — no extra state management needed.

Error Boundaries

import { useRouteError, isRouteErrorResponse } from 'react-router'
export function ErrorBoundary() {
const error = useRouteError()
if (isRouteErrorResponse(error)) {
return (
<div>
<h1>{error.status} {error.statusText}</h1>
<p>{error.data}</p>
</div>
)
}
return (
<div>
<h1>Something went wrong</h1>
<p>{error instanceof Error ? error.message : 'Unknown error'}</p>
</div>
)
}

